package com.aadil.jobtracker.security;import com.aadil.jobtracker.UserRepository.UserRepository;import com.aadil.jobtracker.entity.UserEntity;import org.jspecify.annotations.NonNull;import org.springframework.security.core.userdetails.User;import org.springframework.security.core.userdetails.UserDetails;import org.springframework.security.core.userdetails.UserDetailsService;import org.springframework.security.core.userdetails.UsernameNotFoundException;import org.springframework.stereotype.Service;import java.util.ArrayList;@Servicepublic class JWTUserServiceDetails implements UserDetailsService {    private final UserRepository userRepository;    public JWTUserServiceDetails(UserRepository userRepository) {        this.userRepository = userRepository;    }    @Override    public @NonNull UserDetails loadUserByUsername(String email) throws UsernameNotFoundException {        UserEntity user= userRepository.findByEmail(email.trim().toLowerCase()).orElseThrow(()->new RuntimeException("Email NOT found"));        return new User(user.getEmail(),user.getPassword(),new ArrayList<>());    }}